SELECT 
    da.MaDuAn,
    da.TenDuAn,
    COUNT(DISTINCT cv.MaCongViec) AS SoCongViec,
    COUNT(DISTINCT ct.MaChiTietCV) AS SoChiTiet
FROM [dbo].[DU_AN] da
JOIN [dbo].[DANH_MUC_CONG_VIEC] dm
    ON dm.MaDuAn = da.MaDuAn
JOIN [dbo].[CONG_VIEC] cv
    ON cv.MaDanhMucCV = dm.MaDanhMucCV
LEFT JOIN [dbo].[CT_CONG_VIEC] ct
    ON ct.MaCongViec = cv.MaCongViec
WHERE da.MaDuAn BETWEEN 4 AND 10
GROUP BY da.MaDuAn, da.TenDuAn
ORDER BY da.MaDuAn;
GO

SELECT
    da.MaDuAn,
    da.TenDuAn,
    cv.MaCongViec,
    cv.TenCongViec,
    COUNT(DISTINCT ct.MaChiTietCV) AS SoChiTiet,
    COUNT(DISTINCT pccv.MaNguoiDung) AS SoNguoiPhuTrachCongViec
FROM [dbo].[DU_AN] da
JOIN [dbo].[DANH_MUC_CONG_VIEC] dm
    ON dm.MaDuAn = da.MaDuAn
JOIN [dbo].[CONG_VIEC] cv
    ON cv.MaDanhMucCV = dm.MaDanhMucCV
LEFT JOIN [dbo].[CT_CONG_VIEC] ct
    ON ct.MaCongViec = cv.MaCongViec
LEFT JOIN [dbo].[PHAN_CONG_CONG_VIEC] pccv
    ON pccv.MaCongViec = cv.MaCongViec
WHERE da.MaDuAn BETWEEN 4 AND 10
GROUP BY
    da.MaDuAn,
    da.TenDuAn,
    cv.MaCongViec,
    cv.TenCongViec
ORDER BY da.MaDuAn, cv.MaCongViec;
GO
